function softmaxPick(items, scoreSelector, temperature = 1) {
  if (!items || items.length === 0) return null;
  const safeTemp = Math.max(0.05, temperature);
  const maxScore = Math.max(...items.map(scoreSelector));

  const weighted = [];
  let total = 0;
  for (const item of items) {
